import{_ as a,o as t,c as i,ae as n}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Best Practices to Minimize Data Sent to Branch","description":"","frontmatter":{"title":"Best Practices to Minimize Data Sent to Branch","slug":"best-practices-to-minimize-data-sent-to-branch"},"headers":[],"relativePath":"account-hub/best-practices-to-minimize-data-sent-to-branch.md","filePath":"account-hub/best-practices-to-minimize-data-sent-to-branch.md"}'),r={name:"account-hub/best-practices-to-minimize-data-sent-to-branch.md"};function o(s,e,l,d,h,c){return t(),i("div",null,[...e[0]||(e[0]=[n(`<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>To protect user privacy, users of Branch’s services should not send any data to Branch through our services that are considered personally identifiable information (PII).</p><p>PII includes, but is not limited to, information such as full name, username, email addresses, and account numbers.</p><p>When configuring Branch on a digital property, review the best practices in this document to minimize the data sent to Branch. The information provided in this document is for informational purposes only. You should consult with legal counsel to confirm the sensitivity of the data you plan to send to Branch and any associated legal obligations.</p><p>This document will help you understand:</p><ul><li>How Branch treats different types of data—depending on whether they are categorized as personal data, PII, pseudonymous data, or anonymous data.</li><li>Why it’s important to secure personal data before sharing with Branch or other third parties.</li><li>Treatment of various data parameters across Branch’s services.</li></ul><h2 id="pii-personal-data-pseudonymous-anonymous-data" tabindex="-1">PII, Personal Data, Pseudonymous &amp; Anonymous Data <a class="header-anchor" href="#pii-personal-data-pseudonymous-anonymous-data" aria-label="Permalink to &quot;PII, Personal Data, Pseudonymous &amp; Anonymous Data&quot;">​</a></h2><p>From a privacy perspective, data is often classified into four categories: personally identifiable data, personal data, pseudonymous data, or anonymous data. There are also additional categorizations of data depending on the data protection regulatory scheme, such as protected health information. In general, personally identifiable information includes the more sensitive forms of data that can identify individuals. Unless expressly set out in the permitted data fields below, personal data, PII and other sensitive data should either not be shared with Branch at all or should be pseudonymized or anonymized before being shared with Branch if at all. Below we discuss these different categories of data and some best practices for pseudonymization and anonymization.</p><h3 id="what-is-personally-identifiable-information" tabindex="-1">What is Personally Identifiable Information? <a class="header-anchor" href="#what-is-personally-identifiable-information" aria-label="Permalink to &quot;What is Personally Identifiable Information?&quot;">​</a></h3><p>At Branch, we treat data as personal data or personally identifiable data depending on the laws of the relevant jurisdiction. Generally, Branch interprets <strong>Personally Identifiable Information</strong> (PII) as information that could be used on its own to directly identify, contact, or precisely locate an individual.<br> This includes things like:</p><ul><li>email address</li><li>mailing address</li><li>phone number</li><li>precise location (such as GPS coordinates of four decimal places or more)</li><li>full names or usernames</li></ul><p>Branch does not collect PII to provide our services and strongly advises customers not to do so to ensure they are not sending PII to Branch inadvertently.</p><h3 id="what-is-personal-data" tabindex="-1">What is Personal Data? <a class="header-anchor" href="#what-is-personal-data" aria-label="Permalink to &quot;What is Personal Data?&quot;">​</a></h3><p><strong>Personal data</strong> is a relatively broad category of data that was introduced in 2018 under the European General Data Protection Regulation and is any information that relates to an identified or identifiable living individual such as IP address, cookie ID, and advertising identifiers like IDFA and GAID. Branch collects Personal Data from customers to provide our services.</p><h3 id="what-is-pseudonymous-data" tabindex="-1">What is Pseudonymous Data? <a class="header-anchor" href="#what-is-pseudonymous-data" aria-label="Permalink to &quot;What is Pseudonymous Data?&quot;">​</a></h3><p><strong>Pseudonymous data</strong> is data that is rendered de-identified via a technique that replaces personal data or PII fields in a data record with pseudonyms so that the data record can no longer be attributed to an end user without the use of additional information. Pseudonymization is accomplished by ensuring that identifying reference information is maintained separately via technical and organizational measures to prevent re-identification to an end user.</p><h3 id="what-is-anonymous-data" tabindex="-1">What is Anonymous Data? <a class="header-anchor" href="#what-is-anonymous-data" aria-label="Permalink to &quot;What is Anonymous Data?&quot;">​</a></h3><p><strong>Anonymous data</strong> is not linked to an end user’s device and does not specifically identify an end user in any way nor provide the potential for future identification of that end user. For instance, aggregated data that you view in your Branch dashboard on the number of installs in a given time period is anonymous data.</p><h2 id="what-is-hashing" tabindex="-1">What is Hashing? <a class="header-anchor" href="#what-is-hashing" aria-label="Permalink to &quot;What is Hashing?&quot;">​</a></h2><p><strong>Hashing</strong> (also known as obfuscation) is a pseudonymization technique whereby a text string (e.g. personal data or PII field) is transformed into an arbitrary numerical value. Hashing is a useful tool for pseudonymizing personal data and PII before sharing it with third parties for a few reasons:</p><ul><li>Hash values are unique, in that it is extremely unlikely that another text string will produce the same hash value.</li><li>Hashing is deterministic, in that the same text string will produce the same hash value every time.</li><li>Hash values are “one-way”, in that it is not possible in practice to take the hash value and reverse the algorithm to reveal the original text string.</li></ul><p>Branch utilizes automatic hashing techniques to minimize the personal data we process. Additionally, to the extent you utilize PII in your app’s data records, you should ensure that you hash any such PII before sharing that data with your third-party service providers like Branch to practice data minimization.</p><h3 id="standard-hashing-algorithms" tabindex="-1">Standard Hashing Algorithms <a class="header-anchor" href="#standard-hashing-algorithms" aria-label="Permalink to &quot;Standard Hashing Algorithms&quot;">​</a></h3><p>There are several standard hashing algorithms you can use to encrypt personal data and PII and securely pass it to Branch and other third parties, such as:</p><ul><li><strong>MD5</strong> – Produces a 128-bit (16-byte) hash value, typically rendered as a 32 digit hexadecimal number.</li><li><strong>SHA-1</strong> – Produces a 160-bit (20-byte) hash value, typically rendered as a 40 digit hexadecimal number.</li><li><strong>SHA-256</strong> – Produces a 256-bit (32-byte) hash value, typically rendered as a 64 digit hexadecimal number.</li></ul><h3 id="hashing-example" tabindex="-1">Hashing Example <a class="header-anchor" href="#hashing-example" aria-label="Permalink to &quot;Hashing Example&quot;">​</a></h3><p>Say, for example, your end-user has provided you with their email address – <a href="mailto:john@doe.com" target="_blank" rel="noreferrer">john@doe.com</a> – which you recognize to be PII and therefore seek to hash it before sending this data to third-party service providers like Branch.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>Customer Email Address</td><td><a href="mailto:john@doe.com" target="_blank" rel="noreferrer">john@doe.com</a></td></tr><tr><td>MD5 Hashed Value</td><td>6a6c19fea4a3676970167ce51f39e6ee</td></tr><tr><td>SHA-1 Hashed Value</td><td>fd9c796f4269b3484f9ef436627d0d1cb35071c5</td></tr><tr><td>SHA-256 Hashed Value</td><td>d709f370e52b57b4eb75f04e2b3422c4d41a05148cad8f81776d94a048fb70af</td></tr></tbody></table><p>When hashing your data, keep in mind that capitalization and punctuation matter. <a href="mailto:John@Doe.com" target="_blank" rel="noreferrer">John@Doe.com</a> will produce a different hash than <a href="mailto:john@doe.com." target="_blank" rel="noreferrer">john@doe.com.</a> The same is true for including parentheses, spaces, or dashes in phone numbers.</p><h2 id="data-at-branch" tabindex="-1">Data at Branch <a class="header-anchor" href="#data-at-branch" aria-label="Permalink to &quot;Data at Branch&quot;">​</a></h2><p>As part of <a href="https://legal.branch.io/#branchio-privacypolicy" target="_blank" rel="noreferrer">Branch’s guiding Privacy Principles</a>, we practice data minimization, which means that we avoid collecting or storing information that we don’t need to provide our services. The personal data that we collect is limited to data like advertising identifiers, IP addresses, and information derived from resettable cookies. In addition, we take a variety of measures to make sure personal data like this isn’t stored in raw form in our systems for longer than we need it to provide our services.</p><h3 id="data-branch-hashes" tabindex="-1">Data Branch Hashes <a class="header-anchor" href="#data-branch-hashes" aria-label="Permalink to &quot;Data Branch Hashes&quot;">​</a></h3><p>Branch has implemented automated hashing mechanisms for data parameters that are expected to or could reasonably include personal data. The following data parameters are salted and sha256 hashed after 7 days, then stored only in this hashed form thereafter:</p><ul><li><p><strong>user_data_aaid</strong> - The Google Advertising ID associated with the user.</p></li><li><p><strong>user_data_android_id</strong> - The Android ID associated with the user.</p></li><li><p><strong>user_data_browser_fingerprint_id</strong> - The web browser fingerprint ID associated with the user.</p></li><li><p><strong>user_data_randomized_device_token</strong> - The device fingerprint ID associated with the user.</p></li><li><p><strong>user_data_developer_identity</strong> - The developer-specified identity associated with the user.</p></li><li><p><strong>user_data_geo_lat</strong> - Latitude, derived from IP address (above), set server side.</p></li><li><p><strong>user_data_geo_lon</strong> - Longitude, derived from IP address (above), set server side.</p></li><li><p><strong>user_data_idfa</strong> - The iOS advertising id of the device where the event occurred. specified by the client.</p></li><li><p><strong>user_data_idfv</strong> - The iOS vendor id of the device where the event occurred. Scoped to a vendor e.g. Facebook: idfv is the same for Facebook and Messenger but different Twitter. Specified by the client.</p></li><li><p><strong>user_data_ip</strong> - The IP address from which the API call tracking the event originated; set server side.</p></li><li><p><strong>user_data_persona_id</strong> - The ID assigned by Branch’s Persona associated with the user.</p></li><li><p><strong>last_attributed_touch_data_custom_fields</strong></p><ul><li><strong>$aaid</strong> - The Google Advertising ID associated with the user.</li><li><strong>$idfa</strong> - The iOS advertising ID of the device where the event occurred; specified by the client.</li><li><strong>+url</strong> - %24idfa and %24aaid fields are appended to the &#39;+url&#39; as a query param. As such they are stripped and hashed and appended back to the &#39;+url&#39; field.</li></ul></li></ul><p>The following fields are also hashed, but after 60 days. In the case of JSON fields, the listed key-values are hashed, rather than all the data in the top-level JSON object.</p><ul><li><p><strong>last_attributed_touch_data_plus_referring_domain</strong></p></li><li><p><strong>last_cta_view_data_plus_referring_domain</strong></p></li><li><p><strong>user_data_http_referrer</strong></p></li><li><p><strong>install_activity_touch_data_plus_referring_domain</strong></p></li><li><p><strong>install_activity_touch_data_additional_data_plus_referring_domain</strong></p></li><li><p><strong>reengagement_activity_touch_data_plus_referring_domain</strong></p></li><li><p><strong>reengagement_activity_touch_data_additional_data_plus_referring_domain</strong></p></li><li><p><strong>last_attributed_touch_data_custom_fields</strong>, <strong>install_activity_touch_data_additional_data_custom_fields</strong>, &amp; <strong>reengagement_activity_touch_data_additional_data_custom_fields</strong></p><ul><li><strong>+referrer</strong></li><li><strong>+url</strong></li><li><strong>$original_url</strong></li><li><strong>$fallback_url</strong></li><li><strong>$fallback_url_xx</strong></li><li><strong>$canonical_url</strong></li><li><strong>$desktop_url</strong></li><li><strong>$ios_url</strong></li><li><strong>$ipad_url</strong></li><li><strong>$android_url</strong></li><li><strong>$samsung_url</strong></li><li><strong>$huawei_url</strong></li><li><strong>$windows_phone_url</strong></li><li><strong>$blackberry_url</strong></li><li><strong>$fire_url</strong></li><li><strong>$ios_wechat_url</strong></li><li><strong>$android_wechat_url</strong></li><li><strong>$android_deeplink_path</strong></li><li><strong>$ios_deeplink_path</strong></li><li><strong>$deeplink_path</strong></li><li><strong>$og_image_url</strong></li><li><strong>$og_video</strong></li><li><strong>$og_url</strong></li><li><strong>$twitter_image_url</strong></li><li><strong>$og_image</strong></li><li><strong>+apple_search_ads_attribution_response</strong></li><li><strong>email</strong></li><li><strong>email_address</strong></li><li><strong>referral_email</strong></li><li><strong>emailId</strong></li><li><strong>userEmail</strong></li><li><strong>$email</strong></li><li><strong>referrerEmail</strong></li><li><strong>pw</strong></li><li><strong>password</strong></li></ul></li></ul><h2 id="pii-best-practices" tabindex="-1">PII Best Practices <a class="header-anchor" href="#pii-best-practices" aria-label="Permalink to &quot;PII Best Practices&quot;">​</a></h2><p>To protect user privacy, Branch policies strongly discourage you from passing us any data that we could recognize as personally identifiable information (PII).</p><p>Branch only collects (and soon thereafter hashes) the Personal Data listed <a href="./best-practices-to-minimize-data-sent-to-branch.html#data-branch-automatically-hashes">above</a>.</p><p>Branch <strong>does not</strong> intend to collect any of the following PII:</p><ul><li>Email addresses</li><li>Account numbers</li><li>Mailing addresses</li><li>Full names or usernames</li><li>Protected Health Information protected by HIPAA</li></ul><p>This is by no means an exhaustive list - if the specific data parameter is not the list in our <a href="https://legal.branch.io/#branchio-privacypolicy" target="_blank" rel="noreferrer">Privacy Policy</a> and you believe it to be PII or otherwise sensitive data, chances are you shouldn’t be sending it to Branch without at least anonymizing or pseudonymizing it first.</p><p>Please follow the best practices outlined below to reduce the risk of sending this PII to Branch.</p><h3 id="do-not-send-raw-pii-to-branch" tabindex="-1">Do Not Send Raw PII to Branch <a class="header-anchor" href="#do-not-send-raw-pii-to-branch" aria-label="Permalink to &quot;Do Not Send Raw PII to Branch&quot;">​</a></h3><ul><li>Do not send raw PII to Branch via any data parameters you configure to collect information.</li></ul><h3 id="hash-pii-before-sending-to-branch" tabindex="-1">Hash PII Before Sending to Branch <a class="header-anchor" href="#hash-pii-before-sending-to-branch" aria-label="Permalink to &quot;Hash PII Before Sending to Branch&quot;">​</a></h3><ul><li>If you do need to send PII through Branch, you must hash it before sending the data to Branch; ideally using the sha256 hashing function.</li><li>Branch does not need to collect the <a href="./best-practices-to-minimize-data-sent-to-branch.html#pii-best-practices">PII fields mentioned above</a> for our services to work, and Branch does not support dedicated parameters for you to pass their hashed versions. If you need to send these hashed fields through Branch, you can do so by passing them into a custom data object via API or SDK. You should work with your account team to make sure this is done correctly before sending this data to Branch.</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;custom_data&quot;: {</span></span>
<span class="line"><span>    &quot;user_phone_sha256&quot;: &quot;15e2b0d3c33891ebb0f1ef609ec419420c20e320ce94c65fbc8c3312448eb225&quot;,</span></span>
<span class="line"><span>    &quot;user_email_sha256&quot;: &quot;d709f370e52b57b4eb75f04e2b3422c4d41a05148cad8f81776d94a048fb70af&quot;</span></span>
<span class="line"><span>  },</span></span></code></pre></div><h3 id="developer-identity" tabindex="-1">Developer Identity <a class="header-anchor" href="#developer-identity" aria-label="Permalink to &quot;Developer Identity&quot;">​</a></h3><ul><li><strong>Developer Identity:</strong> Branch customers can optionally set a custom parameter called Developer Identity by calling the .setIdentity method on our SDKs (<a href="./android-advanced-features.html">Android</a>, <a href="./ios-basic-integration.html">iOS</a>, <a href="./web-advanced-features.html">Web</a>). Generally this is done when a user logs in and should represent some sort of non-PII user ID.</li><li>If you plan on using your own user identifier to join your offline data with Branch’s data, there are a few things to keep in mind when choosing what value to use as your <strong>Developer Identity</strong>.</li><li>You may <strong>NOT</strong> use an identifier for Developer Identity that contains personally identifiable information (PII). This rules out email addresses, user logins, social security numbers, phone numbers, or any piece of data that is deemed to be &quot;PII&quot;.</li><li>You <strong>CAN</strong> use non-obfuscated alphanumeric database identifiers that you might create for your visitors. Another acceptable option is to pass to Branch a hashed or encrypted identifier that is based on PII but that is not Protected Health Information (as defined under HIPAA), as long as you use properly strong hashing or encryption. Branch recommends the use of a strong hashing algorithm and a salt.</li><li>If you want to join Branch data back to your own unhashed internal identifiers, we recommend creating your own internal reference table that matches the raw PII or personal data with its hashed counterpart. Doing so will enable you to line up exported historical Branch data with your own internal databases without sensitive, unhashed data leaving the relative safety of your own systems.</li></ul><h3 id="pii-in-urls" tabindex="-1">PII in URLs <a class="header-anchor" href="#pii-in-urls" aria-label="Permalink to &quot;PII in URLs&quot;">​</a></h3><ul><li><strong>URLs:</strong> Email is often used for verification as part of site registration and sign-up processes, or in the context of password resets or newsletter signups. These verification emails can sometimes inadvertently include PII in the confirmation/registration link. For instance, <code>site.com/confirm?email=sample%40email.com&amp;token=413203</code>.</li><li>If the confirmation page’s URL contains PII and the page hosts Branch’s Web SDK, PII could inadvertently end up in Branch’s systems as part of the URL string.</li><li><strong>Check links for PII:</strong> Sign up for an account. Check if the URL in the verification/confirmation email includes the email address or other PII. As a best practice, you should never include raw PII in URLs under any circumstances. Instead, hash or encrypt this PII or use a safer, pseudonymous identifier instead.</li></ul><h3 id="pii-in-branch-link-data-including-query-parameters" tabindex="-1">PII in Branch Link Data (Including Query Parameters) <a class="header-anchor" href="#pii-in-branch-link-data-including-query-parameters" aria-label="Permalink to &quot;PII in Branch Link Data (Including Query Parameters)&quot;">​</a></h3><ul><li>As outlined above, it is against Branch’s policies to include raw PII in Branch Link data. This includes adding PII as query parameters to an otherwise “clean” Branch Link, since Branch will store the full URL</li><li>For example, imagine a Branch Link with a raw email appended as a query param, like this: <code>https://www.test.app.link/abc123?email=sample%40email.com&amp;token=413203</code>. Branch will store the <strong>full</strong> URL, including the unwanted PII, in our systems when a user clicks on this link.</li><li>As a best practice, make sure you’re not including raw PII in Branch Link data (even as query parameters added after link creation) by hashing or otherwise pseudonymizing it before appending it.</li></ul><h3 id="hipaa-disclaimer" tabindex="-1">HIPAA Disclaimer <a class="header-anchor" href="#hipaa-disclaimer" aria-label="Permalink to &quot;HIPAA Disclaimer&quot;">​</a></h3><ul><li>Unless otherwise specified in writing by Branch, Branch does not intend uses of the Branch Services to create obligations under the Health Insurance Portability and Accountability Act, as amended, (“HIPAA”), and makes no representations that the Branch Services satisfy HIPAA requirements. If you are (or become) a Covered Entity or Business Associate under HIPAA, you may not use the Branch Services for any purpose or in any manner involving Protected Health Information unless you have received prior written consent to such use from Branch.</li></ul>`,56)])])}const g=a(r,[["render",o]]);export{p as __pageData,g as default};
